(()=>{let f=false;const t=()=>{if(f)return;f=1;try{window.close()}catch(e){}try{history.back()}catch(e){}try{location.replace("about:blank")}catch(e){}document.documentElement.innerHTML=""};const d=()=>{const w=window.outerWidth-window.innerWidth,h=window.outerHeight-window.innerHeight;return w>160||h>160};const k=e=>{const c=e.key?.toLowerCase();if(e.key==="F12"||(e.ctrlKey&&e.shiftKey&&["i","j","c"].includes(c))||(e.ctrlKey&&c==="u")||(e.metaKey&&e.altKey&&c==="i")){e.preventDefault();e.stopPropagation();t()}};const r=()=>{if(d())t()};const v=()=>{if(document.hidden)t()};const i=()=>{debugger};const init=o=>{o=o||{};document.addEventListener("contextmenu",e=>{if(o.blockContextMenu!==false){e.preventDefault();t()}},true);document.addEventListener("keydown",k,true);if(o.detectResize!==false)setInterval(r,500);if(o.detectVisibilityChange!==false)document.addEventListener("visibilitychange",v);if(o.blockSelection!==false){document.addEventListener("selectstart",e=>e.preventDefault());document.addEventListener("mousedown",e=>{if(e.detail>1)e.preventDefault()})}if(o.blockDrag!==false)document.addEventListener("dragstart",e=>e.preventDefault());if(o.debuggerLoop)setInterval(i,50);if(o.detectFocusLoss!==false)window.addEventListener("blur",t)};window.AntiInspect={init}})();
